      expect(jiraUniversalAvatarMock.storeAvatar).toHaveBeenCalledTimes(1);
      const callArgs = jiraUniversalAvatarMock.storeAvatar.mock.calls[0]!;
      expect(callArgs[0]).toBe('project');
